var SchSelectionPopMenu = class extends KCUIElement {
  static {
    __name(this, "SchSelectionPopMenu");
  }
  static {
    this.styles = [
      css`
            :host {
                position: fixed;
                display: block;
                height: 100%;
                width: 100%;
                background: transparent;
                color: var(--pop-menu-fg);
                z-index: 10; /* Set a higher z-index for the modal */
            }

            /* Style the list inside the modal */
            .modal-list {
                background-color: var(--pop-menu-bg);
                position: absolute;
                display: block;
                border-radius: 5px;
                box-shadow: 0 0 10px rgba(0, 0, 0, 0.3);
                list-style-type: none;
                padding: 0;
                color: var(--pop-menu-fg);
                z-index: 300; /* Set a higher z-index for the list */
            }

            .modal-list li {
                color: var(--pop-menu-fg);
                margin-bottom: 8px;
                cursor: pointer;
                transition: color 0.3s; /* Add transition for smooth hover effect */
            }

            .modal-list li:hover {
                color: var(
                    --pop-menu-fg-hover
                ); /* Set your desired hover color */
            }
        `
    ];
  }
  #net_items = [];
  #content;
  #pos = null;
  constructor() {
    super();
    this.hidden = true;
  }
  connectedCallback() {
    (async () => {
      this.viewer = await this.requestLazyContext("viewer");
      await this.viewer.loaded;
      super.connectedCallback();
      this.setup_events();
    })();
  }
  setup_events() {
    window.addEventListener("mousemove", (e) => {
      this.#pos = new Vec2(e.offsetX, e.offsetY);
    });
    this.addEventListener("click", (event) => {
      if (this.#content.contains(event.target)) {
        return;
      }
      if (event.button === 0 && this.hidden === false) {
        this.hidden = true;
      }
    });
    this.addEventListener(KiCanvasFitterMenuEvent.type, (e) => {
      this.#net_items = e.detail.items;
      if (!this.#net_items.length) {
        this.hidden = true;
      } else {
        if (!this.#pos) return;
        this.update();
        this.#content.style.top = `${this.#pos.y - 10}px`;
        this.#content.style.left = `${this.#pos.x}px`;
        this.hidden = false;
      }
    });
  }
  build_item_desc(itm) {
    return `${itm.sheet_name}:${itm.name}`;
  }
  render() {
    this.#content = html` <ul class="modal-list"></ul>`;
    for (const i of this.#net_items) {
      const selection = html` <li>${this.build_item_desc(i)}</li> `;
      selection.addEventListener("click", () => {
        this.viewer.dispatchEvent(
          new NetItemSelectEvent({
            sheet: i.sheet_name,
            uuid: i.uuid
          })
        );
      });
      this.#content.appendChild(selection);
    }
    return html` ${this.#content} `;
  }
};
window.customElements.define("kc-sch-selection-menu", SchSelectionPopMenu);

// src/kicanvas/elements/kc-schematic/app.ts
var KCSchematicAppElement = class extends KCViewerAppElement {
  static {
    __name(this, "KCSchematicAppElement");
  }
  #selection_pop_menu;
  assert_type() {
    return 0 /* SCH */;
  }
  make_property_element() {
    return html`<kc-schematic-properties-panel></kc-schematic-properties-panel>`;
  }
  make_fitter_menu() {
    const preview = new SchPreviewListElement();
    return preview;
  }
  get sch_viewer() {
    return this.viewer;
  }
  initialContentCallback() {
    super.initialContentCallback();
    this.viewer.addEventListener(SheetChangeEvent.type, (e) => {
      const sch = this.project.file_by_name(e.detail);
      if (sch instanceof KicadSch) this.viewer.load(sch);
    });
    this.viewer.addEventListener(SheetLoadEvent.type, (e) => {
      if (this.#selection_pop_menu)
        this.#selection_pop_menu.hidden = true;
      this.dispatchEvent(new SheetLoadEvent(e.detail));
    });
    this.viewer.addEventListener(NetItemSelectEvent.type, async (e) => {
      this.#select_item(e.detail);
    });
    this.viewer.addEventListener(
      HierarchicalSheetPinClickEvent.type,
      (e) => {
        const it = this.project.find_net_item(e.detail.uuid);
        if (!it) return;
        this.pop_up_label_ref_menu([it]);
      }
    );
    window.addEventListener(SelectDesignatorEvent.type, (e) => {
      const uuid = this.project.find_designator(
        e.detail.designator
      )?.uuid;
      if (uuid)
        this.#select_item({
          sheet: e.detail.sheet,
          uuid
        });
      else {
        console.log(`cannot find designator ${e.detail.designator}`);
      }
    });
    window.addEventListener(ComponentERCResultEvent.type, (e) => {
      Project.import_cjk_glyphs();
      const component_erc_result = e.detail;
      const sch_symbol = this.project.find_designator(
        component_erc_result.designator
      );
      if (sch_symbol) {
        if (sch_symbol.sheet_name !== this.sch_viewer.sch_name) {
          const sch = this.project.file_by_name(
            sch_symbol.sheet_name
          );
          if (sch instanceof KicadSch) {
            this.viewer.load(sch);
          }
        }
        setTimeout(() => {
          this.sch_viewer.show_erc(
            sch_symbol.uuid,
            component_erc_result.pins
          );
        }, 500);
      } else {
        console.warn(
          `ERC: Cannot find designator ${component_erc_result.designator}`
        );
      }
    });
    this.viewer.addEventListener(LabelClickEvent.type, (e) => {
      const its = this.project.find_labels_by_name(e.detail.name);
      if (!its) return;
      this.pop_up_label_ref_menu(
        its.filter((it) => it.uuid !== e.detail.uuid)
      );
    });
    this.renderRoot.addEventListener("erc-jump", (e) => {
      const { designator, pins } = e.detail;
      const sch_symbol = this.project.find_designator(designator);
      if (sch_symbol) {
        if (sch_symbol.sheet_name !== this.sch_viewer.sch_name) {
          const sch = this.project.file_by_name(
            sch_symbol.sheet_name
          );
          if (sch instanceof KicadSch) {
            this.viewer.load(sch);
          }
        }
        setTimeout(() => {
          this.sch_viewer.show_erc(sch_symbol.uuid, pins);
        }, 100);
      } else {
        console.warn(`ERC: Cannot find designator ${designator}`);
      }
    });
    window.addEventListener(ProjectERCResultEvent.type, (e) => {
      console.log("Project ERC Result", e.detail);
      const inspector = this.renderRoot.querySelector("kc-erc-inspector");
      if (inspector && e.detail) {
        inspector.ercResult = e.detail;
      }
    });
  }
  #select_item(idx) {
    const sch = this.project.file_by_name(idx.sheet);
    if (sch instanceof KicadSch) {
      if (sch.filename === this.sch_viewer.sch_name) {
        this.sch_viewer.zoom_fit_item(idx.uuid);
      } else {
        this.sch_viewer.focus_net_item = idx.uuid;
        this.viewer.load(sch);
      }
    }
  }
  pop_up_label_ref_menu(refs) {
    this.#selection_pop_menu.dispatchEvent(
      new KiCanvasFitterMenuEvent({ items: refs })
    );
  }
  on_viewer_select(item, previous) {
    if (!item || item != previous) {
      return;
    }
    if (item instanceof SchematicSheet) {
      this.project.activate_sch(
        `${item.sheetfile}:${item.path}/${item.uuid}`
      );
      return;
    }
  }
  can_load(src) {
    return src instanceof KicadSch;
  }
  do_render() {
    this.#selection_pop_menu = html`<kc-sch-selection-menu></kc-sch-selection-menu>`;
    const inspector = html`<kc-erc-inspector></kc-erc-inspector>`;
    const content = super.render_viewer();
    return html`${content} ${this.#selection_pop_menu} ${inspector}`;
  }
  make_viewer_element() {
    return html`<kc-schematic-viewer></kc-schematic-viewer>`;
  }
};
window.customElements.define("kc-schematic-app", KCSchematicAppElement);

